import React, { useState, useEffect } from 'react';
import NoteCard from '../Notes/NoteCardd'; // Adjust path based on your structure
import NoteModal from '../components/NoteModal'; // Adjust path

const NotesPage = () => {
  const [notes, setNotes] = useState([]); // Array of notes
  const [selectedNote, setSelectedNote] = useState(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [loading, setLoading] = useState(true); // For loading state

  // Simulate fetching notes (replace with API call, e.g., using useNotes hook)
  useEffect(() => {
    // Example: Fetch from your Node.js backend
    // const fetchNotes = async () => {
    //   const response = await api.get('/notes');
    //   setNotes(response.data);
    //   setLoading(false);
    // };
    // fetchNotes();

    // Simulated data for now
    setTimeout(() => {
      setNotes([
        { id: 1, title: 'Sample Note 1', content: 'This is the content of the first note. It can be longer and include multiple lines.', date: new Date('2023-12-01') },
        { id: 2, title: 'Sample Note 2', content: 'Another note with some details.', date: new Date('2023-12-15') },
        // Add more as needed
      ]);
      setLoading(false);
    }, 1000); // Simulate API delay
  }, []);

  const handleOpenModal = (note) => {
    setSelectedNote(note);
    setIsModalOpen(true);
  };

  const handleCloseModal = () => {
    setIsModalOpen(false);
    setSelectedNote(null);
  };

  const handleSaveNote = (updatedNote) => {
    // Update notes array (replace with API call, e.g., api.put(`/notes/${updatedNote.id}`, updatedNote))
    setNotes(notes.map(note => note.id === updatedNote.id ? updatedNote : note));
  };

  if (loading) {
    return <div className="text-center mt-10">Loading notes...</div>; // Simple loading state
  }

  return (
    <div className="container mx-auto p-4">
      <h1 className="text-3xl font-bold text-center mb-6 text-gray-800">My Notes</h1>
      {notes.length === 0 ? (
        <p className="text-center text-gray-600">No notes yet. Create one from the home page!</p>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {notes.map(note => (
            <NoteCard key={note.id} note={note} onOpenModal={handleOpenModal} />
          ))}
        </div>
      )}
      <NoteModal
        note={selectedNote}
        isOpen={isModalOpen}
        onClose={handleCloseModal}
        onSave={handleSaveNote}
      />
    </div>
  );
};

export default NotesPage;
